code = """import json
import re

# Load the joined data from the previous query
joined_file = locals()['var_functions.query_db:46']
with open(joined_file, 'r') as f:
    joined_data = json.load(f)

print('Loaded ' + str(len(joined_data)) + ' joined records')

# Extract package info and stars
package_versions = {}

for rec in joined_data:
    try:
        version_info = json.loads(rec['VersionInfo'])
        is_release = version_info.get('IsRelease', False)
        ordinal = version_info.get('Ordinal', 0)
        
        if is_release:
            name = rec['Name']
            stars_match = re.search(r'(\d+(?:,\d+)*)\s+stars', rec['Project_Information'])
            stars = int(stars_match.group(1).replace(',', '')) if stars_match else 0
            
            if name not in package_versions or ordinal > package_versions[name]['Ordinal']:
                package_versions[name] = {
                    'Name': name,
                    'Version': rec['Version'],
                    'Stars': stars,
                    'Ordinal': ordinal
                }
    except:
        continue

print('Found ' + str(len(package_versions)) + ' latest NPM releases')

# Get top 5 by stars
top5 = sorted(package_versions.values(), key=lambda x: x['Stars'], reverse=True)[:5]

result = [{'Name': pkg['Name'], 'Version': pkg['Version'], 'Stars': pkg['Stars']} for pkg in top5]

print('Top 5:')
for pkg in top5:
    print('  ' + pkg['Name'] + ' v' + pkg['Version'] + ': ' + str(pkg['Stars']) + ' stars')

print('__RESULT__:')
print(json.dumps(result))"""

